const items = $input.all();
const html = items[0].json.data || "";

const jsonMatch = html.match(/<script\b[^>]*type="application\/json"[^>]*>([\s\S]*?pageProps[\s\S]*?)<\/script>/);

if (!jsonMatch) {
    return [{ json: { error: "Failed to extract JSON with offers" } }];
}

try {
    const fullData = JSON.parse(jsonMatch[1].trim());
    const ads = fullData?.props?.pageProps?.data?.searchAds?.items || 
                fullData?.props?.pageProps?.apolloState?.data?.searchAds?.items || [];

    if (ads.length === 0) return [];

    return ads.map(ad => ({
        json: {
            external_id: "OT-" + ad.id,
            category: "mieszkanie-krakow",
            url: "https://www.otodom.pl/pl/oferta/" + ad.slug,
            title: "Oferta OT: " + ad.title,
            price: ad.totalPrice?.value || 0,
            price_per_m2: ad.pricePerSquareMeter?.value || 0,
            area: ad.areaInSquareMeters || 0,
            rooms: ad.roomsNumber || 0,
            lot_size: 0,
            construction_year: 0,
            created_at: new Date().toISOString(),
            property_portal: 'Otodom'          
        }
    }));

} catch (e) {
    return [{ json: { error: "JSON parsing error: " + e.message } }];
}

const items = $input.all();
const results = [];

for (const item of items) {
    // 1. Try to get HTML from various possible locations in n8n
    let html = "";

    if (item.binary && item.binary.data) {
        // If configured as "File"
        html = Buffer.from(item.binary.data.data, 'base64').toString('utf-8');
    } else if (typeof item.json === 'string') {
        html = item.json;
    } else if (item.json && item.json.data) {
        html = item.json.data;
    } else {
        // Last resort: convert everything received to text
        html = JSON.stringify(item.json);
    }

    // 2. Search for offer links (format: /something/8digitnumber.html)
    // Using wider ID range (7-10 digits) as numbers keep growing
    const regex = /href="([^"]+?\/(\d{7,10})\.html)"/g; 
    let match;

    while ((match = regex.exec(html)) !== null) {
        let rawUrl = match[1];
        const id = match[2];

        // 3. Build full, correct URL with ?i parameter
        const fullUrl = rawUrl.startsWith('http') 
            ? rawUrl 
            : `https://www.nieruchomosci-online.pl${rawUrl}`;

        results.push({
            external_id: `NO-${id}`,
            url: fullUrl + "?i",
            category: "mieszkanie-krakow",
            title: `Oferta NO: ${id}`,
            price: 0,
            price_per_m2: 0,
            area: 0,
            lot_size: 0,
            construction_year: 0,
            created_at: new Date().toISOString(),
            property_portal: 'Nieruchomości online'
        });
    }
}

// 4. Remove duplicates by ID
const uniqueMap = new Map();
results.forEach(res => uniqueMap.set(res.external_id, res));

return Array.from(uniqueMap.values()).map(json => ({ json }));

// 1. Get HTML from current input (HTTP Request)
const allHtmlInputs = $input.all();

// 2. Get data directly from the preceding SQL node
// Using .all() to match the entire list of records
const allOffersFromSql = $("Execute a SQL query - Add offer").all();

return allHtmlInputs.map((htmlItem, index) => {
  // Get data from DB for the same index
  const sqlRecord = allOffersFromSql[index] ? allOffersFromSql[index].json : {};

  return {
    ...sqlRecord, // This carries over ai_rating, external_id and everything else from SQL
    raw_html: htmlItem.json.data || "No HTML content"
  };
});

const offer = $("Wait").first().json || {};
const feedbackHint = $json.feedback_hint || 'No feedback hint available';

return [{
  json: {
    ...offer,
    feedback_hint: feedbackHint,
    feedback_hint_debug: feedbackHint
  }
}];

const text = $json.output || "";

// Function to extract text between a key and comma/end (for strings)
const extractString = (key) => {
  const regex = new RegExp(`"${key}"\\s*:\\s*"(.*?)"(?=\\s*[,}])`, 's');
  const match = text.match(regex);
  return match ? match[1].replace(/\\"/g, '"').replace(/\\n/g, '\n') : "";
};

// Function to extract numbers
const extractNum = (key) => {
  const regex = new RegExp(`"${key}"\\s*:\\s*(\\d+(?:[.,]\\d+)?)`, 'i');
  const match = text.match(regex);
  return match ? parseFloat(match[1].replace(',', '.')) : 0;
};

// Extract HTML (hardest field - search from key to last quote before closing brace)
const htmlMatch = text.match(/"ai_analysis_html"\s*:\s*"(.*)"\s*}/s);
let htmlContent = htmlMatch ? htmlMatch[1].trim() : "No analysis";

// Clean HTML from escaped quotes (\"), if any remain
htmlContent = htmlContent.replace(/\\"/g, '"').replace(/\\n/g, '<br>');

return [{
  json: {
    ...$json,
    ai_parsed: {
    external_id: extractString("external_id"),
    title: extractString("title"),
    price: extractNum("price"),
    price_per_m2: extractNum("price_per_m2"),
    area: extractNum("area"),
    lot_size: extractNum("lot_size"),
    construction_year: extractNum("construction_year"),
    ai_rating: extractNum("ai_rating"),
    ai_analysis_html: htmlContent
  }
}
}];

